function gpuTier(p) {
  const text = nombreProducto(p);
  if (text.includes('4090')) return 100;
  if (text.includes('7900 xtx')) return 92;
  if (text.includes('4070 super')) return 80;
  if (text.includes('7800 xt')) return 76;
  if (text.includes('4060 ti')) return 63;
  if (text.includes('4060')) return 52;
  if (text.includes('rx 6600') || text.includes('rx6600') || text.includes('6600')) return 42;
  if (text.includes('3050')) return 30;
  return Number(p.gpu_vram_gb || 0) * 4 + Number(p.precio || 0) / 25;
}

function cpuTier(p) {
  const text = nombreProducto(p);
  if (/14900|i9/.test(text)) return 100;
  if (/7800x3d/.test(text)) return 92;
  if (/13700|i7/.test(text)) return 86;
  if (/7700x/.test(text)) return 78;
