  if (/5600x|12400|i5/.test(text)) return 56;
  if (/12100|i3/.test(text)) return 38;
  if (/4500/.test(text)) return 34;
  return Number(p.cpu_nucleos || 0) * 7 + Number(p.cpu_hilos || 0) * 2;
}

function ramTier(p) {
  const gb = Number(p.ram_gb || 0);
  if (gb >= 32 && gb <= 48) return 92;
  if (gb >= 16) return 78;
  if (gb >= 64) return tipoUso === 'productividad_creativa' ? 100 : 70;
  return gb * 3;
}

function storageTier(p) {
  const text = String(p.alm_tipo || '') + ' ' + String(p.alm_interfaz || '') + ' ' + nombreProducto(p);
  let score = Number(p.precio || 0) / 8;
