function precioTotal(build) {
  return Object.values(build)
    .filter(Boolean)
    .reduce((sum, p) => sum + Number(p.precio || 0), 0);
}

function buildScore(build) {
  const total = precioTotal(build);
  const balancedPc = (tipoUso === 'gaming' || tipoUso === 'general') && categoriasSolicitadas.includes('Tarjeta grafica');

