      if (/a520/.test(placaText) && (gpuScore > 55 || cpuScore > 55)) score -= 850;
      if (/b660/.test(placaText) && cpuScore > 82) score -= 700;
      if (placaPrice < 105 && (gpuScore > 70 || cpuScore > 70)) score -= 500;
    }

    if (fuente && gpu) {
      const margen = Number(fuente.fuente_watts || 0) - Number(gpu.gpu_consumo_w || 0);
      score += Math.max(-250, Math.min(90, margen * 0.6));
    }

    if (placa) score -= Math.max(0, Number(placa.precio || 0) - 240) * 4.2;
    if (ram && tipoUso !== 'productividad_creativa') score -= Math.max(0, Number(ram.ram_gb || 0) - 32) * 18;
    if (gab) score -= Math.max(0, Number(gab.precio || 0) - 130) * 1.6;
    if (fuente) score -= Math.max(0, Number(fuente.precio || 0) - 140) * 0.9;

    if (presupuesto) {
      const budget = Number(presupuesto);
      const target = budget * (tipoUso === 'gaming' ? 0.93 : 0.86);
      score -= Math.abs(target - total) * 0.08;
      if (total < budget * 0.62) score -= (budget * 0.62 - total) * 0.45;
    }

    if (prioridad === 'precio') score -= total * 0.2;
    else score -= total * 0.03;

    return score;
  }

