    if (!p) continue;
    const sem = productSemanticScore(p);
    if ((tipoUso === 'gaming' || tipoUso === 'gaming_ligero') && cat === 'Tarjeta grafica') semanticScore += sem * (tipoUso === 'gaming_ligero' ? 180 : 650);
    else if ((tipoUso === 'gaming' || tipoUso === 'gaming_ligero') && cat === 'Procesador') semanticScore += sem * (tipoUso === 'gaming_ligero' ? 80 : 250);
    else semanticScore += sem * 120;
    const perf = productPerfScore(p, cat);
    if (tipoUso === 'gaming_ligero' && cat === 'Tarjeta grafica') perfScore += perf * 0.75;
    else if (tipoUso === 'gaming_ligero' && ['Procesador', 'Memoria RAM'].includes(cat)) perfScore += perf * 0.35;
    else if (tipoUso === 'gaming' && cat === 'Tarjeta grafica') perfScore += perf * 6;
    else if (tipoUso === 'gaming' && cat === 'Procesador') perfScore += perf * 1.1;
    else if (tipoUso === 'productividad_creativa' && ['Procesador', 'Memoria RAM', 'Almacenamiento', 'Tarjeta grafica'].includes(cat)) perfScore += perf * 1.8;
    else if (tipoUso === 'oficina') perfScore += cat === 'Tarjeta grafica' ? perf * 0.2 : perf * 0.8;
    else if (tipoUso === 'gaming' && cat === 'Memoria RAM') perfScore += perf * 0.45;
    else perfScore += perf;
  }

  let budgetScore = 0;
  if (presupuesto) {
    const diff = Math.max(0, Number(presupuesto) - total);
    budgetScore = 120 - (diff / Number(presupuesto)) * 40;
  }

  const priceScore = (prioridad === 'precio' || tipoUso === 'gaming_ligero') ? -total * 0.75 : total * 0.05;
  return semanticScore + perfScore + budgetScore + priceScore;
}

function gamingLightUpgradeScore(build) {
