    score += productPerfScore(ram, 'Memoria RAM') * 0.6;
    const gb = Number(ram.ram_gb || 0);
    if (gb >= 16) score += 260;
    if (gb > 16) score += Math.min(80, (gb - 16) * 4);
  }
  if (alm && /nvme|m.2|pcie/i.test(String(alm.alm_tipo || '') + ' ' + String(alm.alm_interfaz || ''))) score += 35;

  if (presupuesto) {
    const budget = Number(presupuesto);
