const displayOrder = ['Procesador', 'Placa madre', 'Memoria RAM', 'Tarjeta grafica', 'Fuente de poder', 'Almacenamiento', 'Gabinete'];
const generationOrder = tipoUso === 'productividad_creativa'
  ? ['Procesador', 'Placa madre', 'Memoria RAM', 'Tarjeta grafica', 'Fuente de poder', 'Almacenamiento', 'Gabinete']
  : (tipoUso === 'gaming' || tipoUso === 'general' || tipoUso === 'gaming_ligero')
    ? ['Tarjeta grafica', 'Procesador', 'Placa madre', 'Memoria RAM', 'Fuente de poder', 'Almacenamiento', 'Gabinete']
    : displayOrder;
const categoriasBase = categoriasSolicitadas.filter(cat => Array.isArray(porCategoria[cat]) && porCategoria[cat].length > 0);
const categorias = [
  ...generationOrder.filter(cat => categoriasBase.includes(cat)),
  ...categoriasBase.filter(cat => !generationOrder.includes(cat))
];


function productoTexto(p) {
  return String((p && (p.nombre || p.modelo || p.descripcion)) || '');
}

function creativeGpuScore(gpu) {
  const text = productoTexto(gpu).toLowerCase();
  let score = Number(gpu.gpu_vram_gb || 0) * 48 + gpuTier(gpu) * 8;
  if (text.includes('nvidia') || text.includes('rtx')) score += 700;
  if (text.includes('4090')) score += 420;
  if (text.includes('4070 super')) score += 650;
  if (text.includes('4060 ti')) score += 360;
  if (text.includes('3050') || text.includes('rx 6600') || text.includes('rx6600')) score -= 420;
  return score;
}

function creativeCpuScore(cpu) {
  const text = productoTexto(cpu).toLowerCase();
  let score = Number(cpu.cpu_nucleos || 0) * 75 + Number(cpu.cpu_hilos || 0) * 26 + cpuTier(cpu) * 7;
  if (/7800x3d/.test(text)) score -= 180;
  if (/i7|i9|13700|14900/.test(text)) score += 90;
  return score;
}

function creativeStorageScore(alm) {
  const text = String(alm.alm_tipo || '') + ' ' + String(alm.alm_interfaz || '') + ' ' + productoTexto(alm);
  let score = Number(alm.precio || 0) * 0.5;
  if (/nvme|m.2|pcie/i.test(text)) score += 260;
  if (/hdd/i.test(text)) score -= 260;
  return score;
}

function creativeBuildScore(build) {
  const total = precioTotal(build);
  const cpu = build['Procesador'];
  const gpu = build['Tarjeta grafica'];
  const ram = build['Memoria RAM'];
  const placa = build['Placa madre'];
  const alm = build['Almacenamiento'];
  const fuente = build['Fuente de poder'];

  let score = 0;
  if (gpu) score += creativeGpuScore(gpu) * 2.2;
  if (cpu) score += creativeCpuScore(cpu) * 1.35;
  if (ram) {
    const gb = Number(ram.ram_gb || 0);
    score += gb * 42 + Number(ram.ram_velocidad_mhz || 0) * 0.08;
    if (gb < 32) score -= 900;
    if (gb >= 64) score += 1300;
  }
  if (alm) score += creativeStorageScore(alm);
  if (fuente && gpu) {
    const margen = Number(fuente.fuente_watts || 0) - Number(gpu.gpu_consumo_w || 0);
    score += Math.max(-500, Math.min(180, margen * 0.8));
  }

  if (placa && cpu) {
    const placaText = productoTexto(placa).toLowerCase();
    const cpuText = productoTexto(cpu).toLowerCase();
    if (placaText.includes('a520')) score -= 900;
    if (placaText.includes('b660') && (cpuText.includes('i9') || cpuText.includes('14900'))) score -= 1200;
    if (Number(placa.precio || 0) < 120 && Number(cpu.precio || 0) > 350) score -= 650;
  }

  if (presupuesto) {
    const budget = Number(presupuesto);
    if (total > budget) score -= (total - budget) * 120;
    score -= Math.abs(budget * 0.88 - total) * 0.12;
  }

  score -= total * 0.025;
  return score;
}

function armarWorkstationsCreativas() {
  const cpus = (porCategoria['Procesador'] || []).slice(0, 7);
  const placas = (porCategoria['Placa madre'] || []).slice(0, 6);
  const rams = (porCategoria['Memoria RAM'] || [])
    .filter(r => Number(r.ram_gb || 0) >= 32)
    .slice(0, 6);
  const gpus = (porCategoria['Tarjeta grafica'] || [])
    .filter(g => Number(g.gpu_vram_gb || 0) >= 8)
    .slice(0, 7);
  const fuentes = (porCategoria['Fuente de poder'] || []).slice(0, 5);
  const almacenes = (porCategoria['Almacenamiento'] || [])
    .filter(a => {
      const text = String(a.alm_tipo || '') + ' ' + String(a.alm_interfaz || '') + ' ' + productoTexto(a).toLowerCase();
      return text.includes('nvme') || text.includes('m.2') || text.includes('pcie');
    })
    .slice(0, 7);
  const gabinetes = (porCategoria['Gabinete'] || []).slice(0, 5);

  const resultados = [];
  for (const cpu of cpus) {
    for (const placa of placas) {
      if (cpu.cpu_socket !== placa.placa_socket_cpu) continue;
      for (const ram of rams) {
        if (ram.ram_tipo !== placa.placa_tipo_ram) continue;
        for (const gpu of gpus) {
          for (const fuente of fuentes) {
            if (Number(fuente.fuente_watts || 0) < Number(gpu.gpu_consumo_w || 0)) continue;
            for (const alm of almacenes) {
              for (const gab of gabinetes) {
                const build = {
                  'Procesador': cpu,
                  'Placa madre': placa,
                  'Memoria RAM': ram,
                  'Tarjeta grafica': gpu,
                  'Fuente de poder': fuente,
                  'Almacenamiento': alm,
                  'Gabinete': gab,
                };
                if (!buildEsCompatible(build)) continue;
                const total = precioTotal(build);
                if (presupuesto && total > Number(presupuesto)) continue;
                resultados.push({
                  items: displayOrder.map(cat => build[cat]).filter(Boolean).map((p) => ({
                    id_producto: p.id_producto,
                    categoria: p.categoria,
                    nombre: p.nombre || '',
                    marca: p.marca || '',
                    precio: Number(p.precio || 0),
                  })),
                  total,
                  score: creativeBuildScore(build),
                });
              }
            }
          }
        }
      }
    }
  }

  return resultados.sort((a, b) => b.score - a.score);
}

if (tipoUso === 'productividad_creativa') {
  const buildsCreativas = armarWorkstationsCreativas();
  if (buildsCreativas.length === 0) {
    return [{
      json: {
        fallback: true,
        mensaje: 'No encontré combinaciones compatibles para una workstation creativa con los filtros indicados.',
        builds: [],
        semantic,
        session_id: config.session_id,
      }
    }];
  }

  const budget = Number(presupuesto || 0);
  const elegidasCreativas = [];
  const addCreative = (build) => {
    if (!build) return;
    const sig = build.items.map(p => p.id_producto).sort((a, b) => a - b).join('-');
    if (!elegidasCreativas.some(item => item.items.map(p => p.id_producto).sort((a, b) => a - b).join('-') === sig)) elegidasCreativas.push(build);
  };

  addCreative(buildsCreativas[0]);
  const balanceadas = budget
    ? buildsCreativas.filter(b => b.total <= budget * 0.9 && b.total >= budget * 0.65)
    : buildsCreativas;
  addCreative(balanceadas[0] || buildsCreativas[Math.floor(buildsCreativas.length / 2)]);
  const economicasPro = buildsCreativas
    .filter(b => !budget || (b.total <= budget * 0.75 && b.total >= budget * 0.45))
    .sort((a, b) => a.total - b.total || b.score - a.score);
  addCreative(economicasPro[0] || [...buildsCreativas].sort((a, b) => a.total - b.total)[0]);

  for (const build of buildsCreativas) {
    if (elegidasCreativas.length >= 3) break;
    addCreative(build);
  }

  const queryCreativa = String(config.query_semantica || semantic.query || '').toLowerCase();
  const incluyeAudio = queryCreativa.includes('ableton') || queryCreativa.includes('ozone') || queryCreativa.includes('mixing') || queryCreativa.includes('mastering') || queryCreativa.includes('produccion musical') || queryCreativa.includes('producción musical');
  const incluyeColor = queryCreativa.includes('davinci') || queryCreativa.includes('resolve') || queryCreativa.includes('color grading') || queryCreativa.includes('prores') || queryCreativa.includes('pro res');
  const etiquetasCreativas = incluyeAudio && incluyeColor
    ? ['Workstation color/audio', 'Balance para DaVinci y Ableton', 'Mínima viable']
    : incluyeAudio
      ? ['Workstation para producción musical', 'Balance para Ableton/Ozone', 'Mínima viable']
      : ['Workstation profesional', 'Balance para DaVinci Resolve', 'Mínima viable'];
  return [{
    json: {
      fallback: false,
      builds: elegidasCreativas.slice(0, 3).map((build, index) => ({ etiqueta: etiquetasCreativas[index], ...build })),
      semantic,
      session_id: config.session_id,
    }
  }];
}

function limiteCategoria(cat) {
  if (tipoUso === 'gaming_ligero') {
    if (['Fuente de poder', 'Almacenamiento', 'Gabinete'].includes(cat)) return 3;
    if (cat === 'Tarjeta grafica') return 7;
    return 8;
  }
  if (tipoUso === 'gaming' || tipoUso === 'general') {
    if (['Fuente de poder', 'Almacenamiento', 'Gabinete'].includes(cat)) return 3;
    if (cat === 'Procesador') return 9;
    return 8;
  }
  if (tipoUso === 'productividad_creativa') {
    if (cat === 'Procesador') return 7;
    if (cat === 'Placa madre') return 6;
    if (cat === 'Memoria RAM') return 6;
    if (cat === 'Tarjeta grafica') return 7;
    if (cat === 'Almacenamiento') return 5;
    return 4;
  }
  return 8;
}

function generarBuilds(cats, idx, actual, resultados) {
  if (resultados.length >= (tipoUso === 'productividad_creativa' ? 1800 : 10000)) return;
  if (idx === cats.length) {
    if (!buildEsCompatible(actual)) return;

    const total = precioTotal(actual);
    if (presupuesto && total > Number(presupuesto)) return;

    resultados.push({
      items: Object.entries(actual)
        .filter(([, p]) => p)
        .map(([cat, p]) => ({
          id_producto: p.id_producto,
          categoria: cat,
          nombre: p.nombre || '',
          marca: p.marca || '',
          precio: Number(p.precio || 0)
        }))
        .sort((a, b) => displayOrder.indexOf(a.categoria) - displayOrder.indexOf(b.categoria)),
      total,
      score: buildScore(actual),
      upgradeScore: gamingLightUpgradeScore(actual),
      valueScore: gamingLightValueScore(actual)
    });
    return;
  }

  const cat = cats[idx];
  for (const prod of porCategoria[cat].slice(0, limiteCategoria(cat))) {
    const siguiente = { ...actual, [cat]: prod };
    if (buildEsCompatible(siguiente)) generarBuilds(cats, idx + 1, siguiente, resultados);
    if (resultados.length >= (tipoUso === 'productividad_creativa' ? 1800 : 10000)) return;
  }
}

const buildsValidas = [];
generarBuilds(categorias, 0, {}, buildsValidas);

if (buildsValidas.length === 0) {
  return [{
    json: {
      fallback: true,
      mensaje: 'No encontré combinaciones compatibles con los filtros indicados.',
      builds: [],
      semantic,
      session_id: config.session_id
    }
  }];
}

function signature(build) {
  return build.items.map(p => p.id_producto).sort((a, b) => a - b).join('-');
}

function uniquePush(target, build) {
  if (!build) return;
  if (!target.some(item => signature(item) === signature(build))) target.push(build);
}

const byScore = [...buildsValidas].sort((a, b) => b.score - a.score);
const byPriceAsc = [...buildsValidas].sort((a, b) => a.total - b.total);
const byPriceDesc = [...buildsValidas].sort((a, b) => b.total - a.total);

const elegidas = [];
let etiquetas = ['Alto rendimiento', 'Equilibrada', 'Económica'];

if (tipoUso === 'gaming_ligero') {
  etiquetas = ['Recomendada para e-sports', 'Económica', 'Con margen de mejora'];
  const budget = Number(presupuesto || 0);
  const hasEnoughRam = (build) => build.items.some(p => p.categoria === 'Memoria RAM' && /(16|32|64)GB/i.test(p.nombre || ''));
  const withEnoughRam = buildsValidas.filter(hasEnoughRam);
  const candidates = withEnoughRam.length ? withEnoughRam : buildsValidas;
  const sortedByValue = [...candidates].sort((a, b) => (b.valueScore || 0) - (a.valueScore || 0));
  const sortedByUpgrade = [...candidates].sort((a, b) => (b.upgradeScore || 0) - (a.upgradeScore || 0));
  const economy = [...candidates].sort((a, b) => a.total - b.total)[0];
  const recommendedPool = budget
    ? candidates.filter(b => b.total <= budget * 0.82 && (!economy || b.total >= economy.total + 20))
    : candidates;
  const upgradePool = budget
    ? candidates.filter(b => b.total <= budget && b.total >= budget * 0.7)
    : candidates;

  uniquePush(elegidas, [...recommendedPool].sort((a, b) => (b.valueScore || 0) - (a.valueScore || 0))[0] || sortedByValue[0]);
  uniquePush(elegidas, economy || byPriceAsc[0]);
  uniquePush(elegidas, [...upgradePool].sort((a, b) => (b.upgradeScore || 0) - (a.upgradeScore || 0))[0] || sortedByUpgrade[0] || byPriceDesc[0]);
} else {
  const needsGamingRam = tipoUso === 'gaming' || tipoUso === 'general';
  const hasEnoughRam = (build) => build.items.some(p => p.categoria === 'Memoria RAM' && /(16|32|64)GB/i.test(p.nombre || ''));
  const selectionPool = needsGamingRam ? buildsValidas.filter(hasEnoughRam) : buildsValidas;
  const rankedPool = selectionPool.length ? selectionPool : buildsValidas;
  const rankedByScore = [...rankedPool].sort((a, b) => b.score - a.score);
  const rankedByPriceAsc = [...rankedPool].sort((a, b) => a.total - b.total);
  const budget = Number(presupuesto || 0);
  const balancedPool = budget
    ? rankedPool.filter(b => b.total <= budget * 0.9 && b.total >= budget * 0.72)
    : rankedPool;
  const rankedBalanced = [...(balancedPool.length ? balancedPool : rankedPool)].sort((a, b) => b.score - a.score);

  uniquePush(elegidas, rankedByScore[0]);
  uniquePush(elegidas, prioridad === 'precio' ? rankedByPriceAsc[0] : rankedBalanced[0] || rankedByScore[Math.floor(rankedByScore.length / 2)]);
  uniquePush(elegidas, rankedByPriceAsc[0]);
}

for (const build of byScore) {
  if (elegidas.length >= 3) break;
  uniquePush(elegidas, build);
}
for (const build of byPriceDesc) {
  if (elegidas.length >= 3) break;
  uniquePush(elegidas, build);
}

return [{
  json: {
    fallback: false,
    builds: elegidas.slice(0, 3).map((build, index) => ({ etiqueta: etiquetas[index], ...build })),
    semantic,
    session_id: config.session_id
  }
}];

const data = $('Code in JavaScript6').first().json;
